import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"Java auf Windows installieren","description":"Ein Schritt-für-Schritt-Leitfaden zur Installation von Java auf Windows.","frontmatter":{"title":"Java auf Windows installieren","description":"Ein Schritt-für-Schritt-Leitfaden zur Installation von Java auf Windows.","authors":["IMB11","skycatminepokie"],"next":false,"files":[]},"headers":[],"relativePath":"de_de/players/installing-java/windows.md","filePath":"translated/de_de/players/installing-java/windows.md","lastUpdated":1770561656000}`);var l={name:`de_de/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Java auf Windows installieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Java auf Windows installieren”">​</a></h1><p>Diese Anleitung führt Sie durch die Installation von Java 21 auf Windows.</p><p>Der Minecraft Launcher kommt bereits mit seiner eigenen Java Installation, diese Sektion ist also nur relevant, wenn Sie den Fabric <code>.jar</code> basierten Installer verwenden möchten oder wenn Sie die Minecraft Server <code>.jar</code> verwenden möchten.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Überprüfen, ob Java bereits installiert ist <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Überprüfen, ob Java bereits installiert ist”">​</a></h2><p>Um zu überprüfen, ob Java bereits installiert ist, öffnen Sie die Kommandozeile.</p><p>Dies kannst du machen, indem du <kbd>Windows</kbd>+<kbd>R</kbd> drückst und <code>cmd.exe</code> in das angezeigte Feld eingibst.</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Windows-Ausführungsdialog mit &quot;cmd.exe&quot; in der Ausführungsleiste" loading="lazy"></p><p>Wenn Sie die Kommandozeile geöffnet haben, geben Sie <code>java -version</code> ein und drücken <kbd>Enter</kbd>.</p><p>Wenn der Befehl erfolgreich ausgeführt wird, sollten Sie folgendes sehen. Wenn der Befehl fehlgeschlagen ist, fahren Sie mit dem nächsten Schritt fort.</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Kommandozeile mit &quot;java -version&quot;" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Um Minecraft 1.21.11 zu verwenden, musst du mindestens Java 21 installiert haben.</p><p>Wenn dieser Befehl, eine Version kleiner als 21 anzeigt, musst du deine existierende Java Installation aktualisieren; lies diese Seite weiter.</p></div><h2 id="2-download-the-java-installer" tabindex="-1">2. Herunterladen des Java 21 Installer <a class="header-anchor" href="#2-download-the-java-installer" aria-label="Permalink to “2. Herunterladen des Java 21 Installer”">​</a></h2><p>Um Java 21 zu installieren, musst du den Installer von <a href="https://adoptium.net/temurin/releases?version=21&amp;os=windows&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">Adoptium</a> herunterladen.</p><p>Sie müssen die Version &quot;Windows Installer (.msi)&quot; herunterladen:</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Adoptium Download-Seite mit hervorgehobenem Windows Installer (.msi)" loading="lazy"></p><p>Sie sollten <code>x86</code> wählen, wenn Sie ein 32-Bit-Betriebssystem haben, oder <code>x64</code>, wenn Sie ein 64-Bit-Betriebssystem haben.</p><p>Die meisten modernen Computer sind mit einem 64-Bit-Betriebssystem ausgestattet. Wenn Sie sich unsicher sind, versuchen Sie es mit dem 64-Bit-Download.</p><h2 id="3-run-the-installer" tabindex="-1">3. Installer starten! <a class="header-anchor" href="#3-run-the-installer" aria-label="Permalink to “3. Installer starten!”">​</a></h2><p>Folge den Schritten des Installationsprogramms, um Java 21 zu installieren. Wenn Sie diese Seite erreichen, sollten Sie die folgenden Funktionen auf &quot;Die gesamte Funktion wird auf der lokalen Festplatte installiert&quot; einstellen:</p><ul><li><code>JAVA_HOME Umgebungsvariable setzen</code> - Diese wird zu Ihrem PATH hinzugefügt.</li><li>JavaSoft (Oracle)-Registrierungsschlüssel</li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Java 21-Installationsprogramm mit &quot;JAVA_HOME-Variable setzen&quot; und &quot;JavaSoft (Oracle) Registrierungsschlüssel&quot; hervorgehoben" loading="lazy"></p><p>Wenn Sie das getan haben, können Sie <code>Weiter</code> klicken und mit der Installation fortfahren.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Windows teilt nicht immer anderen Programmen erst nach einem Neustart des Computers mit, dass Java installiert ist.</p><p><strong>Starte deinen Computer unbedingt neu, bevor du fortfährst!</strong></p></div><h2 id="4-verify-that-java-is-installed" tabindex="-1">4. Verifiziere, dass Java 21 installiert ist <a class="header-anchor" href="#4-verify-that-java-is-installed" aria-label="Permalink to “4. Verifiziere, dass Java 21 installiert ist”">​</a></h2><p>Sobald die Installation abgeschlossen ist, kannst du überprüfen, ob Java 21 installiert ist, indem du die Kommandozeile erneut öffnest und <code>java -version</code> eingibst.</p><p>Wenn der Befehl erfolgreich ausgeführt wird, wird die Java-Version wie zuvor gezeigt angezeigt:</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Kommandozeile mit &quot;java -version&quot;" loading="lazy"></p><p>Wenn du Probleme hast, kannst du gerne im <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> im Kanal <code>#player-support</code> um Hilfe bitten.</p>`,28)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};